CREATE TABLE IF NOT EXISTS `content_texts` (`id` CHAR(36) UNIQUE PRIMARY KEY, `key` VARCHAR(255) NOT NULL UNIQUE, `title` VARCHAR(255) NOT NULL, `content` TEXT NOT NULL, `created_at` DATETIME(3) NOT NULL, `updated_at` DATETIME(3) NOT NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
INSERT INTO content_texts (id, `key`, title, content, created_at, updated_at) VALUES ('d251eba6-d167-43f8-ad11-8479db0e92f5', 'about', 'Sobre Nós', 'A Paróquia Santo André é uma comunidade de fé localizada em Tarumã, dedicada ao serviço pastoral e à evangelização. Fundada em 1952, a paróquia tem crescido e se desenvolvido ao longo dos anos, sempre mantendo seu compromisso com os valores cristãos e a transformação social da comunidade. Nossa missão é promover a vida cristã através dos sacramentos, da catequese e do trabalho comunitário.', '2026-02-09 12:47:30.346', '2026-02-09 12:47:30.346');
