INSERT INTO guides (id, title, content, details, icon, created_at, updated_at) VALUES ('4fa4500c-8cae-457a-a689-12cedbeecd6a', 'Guia de Casamento', 'Informações essenciais para celebração do sacramento do matrimônio', '["Documentação necessária (certidão de nascimento, batismo)","Preparação pré-matrimonial (3 encontros obrigatórios)","Entrevista com o pároco","Período de noivado recomendado","Data e horários disponíveis para cerimônia","Orientações sobre a liturgia do matrimônio","Normas sobre padrinhos e convidados","Custos e taxas da paróquia"]', NULL, '2026-02-09 12:47:30.338', '2026-02-09 12:47:30.338');
INSERT INTO guides (id, title, content, details, icon, created_at, updated_at) VALUES ('bd02ce57-45d0-453b-a34d-870c285343b9', 'Guia de Batismo', 'Tudo o que você precisa saber sobre o batismo e iniciação cristã', '["Documentação da criança (certidão de nascimento)","Escolha de padrinhos qualificados","Preparação espiritual dos pais","Entrevista com o pároco ou catequista","Escolha do nome do santo padroeiro","Data e horários disponíveis para batismo","Preparação da vela batismal","Significado dos símbolos batismais"]', NULL, '2026-02-09 12:47:30.338', '2026-02-09 12:47:30.338');
INSERT INTO guides (id, title, content, details, icon, created_at, updated_at) VALUES ('cfe47a39-6e3d-4f33-8e40-d122217a11fa', 'Guia de Catequese', 'Informações sobre os programas de catequese paroquial', '["Catequese infantil (6-12 anos)","Catequese de adolescentes (12-17 anos)","Catequese de adultos","Preparação para Primeira Comunhão","Preparação para Confirmação","Cronograma e dias de encontro","Catequistas responsáveis e horários","Material didático disponível"]', NULL, '2026-02-09 12:47:30.338', '2026-02-09 12:47:30.338');
INSERT INTO guides (id, title, content, details, icon, created_at, updated_at) VALUES ('affbc02f-b38c-4695-9ce8-6ced6c5e1e6b', 'Guia de Coroinha', 'Orientações para crianças que desejam servir no altar', '["Idade mínima recomendada","Treinamento e preparação litúrgica","Uniforme e indumentária","Responsabilidades no altar","Calendário de rodízios e missas","Atividades sociais e confraternizações","Formação espiritual contínua","Requisitos de frequência"]', NULL, '2026-02-09 12:47:30.338', '2026-02-09 12:47:30.338');
INSERT INTO guides (id, title, content, details, icon, created_at, updated_at) VALUES ('4b2a426a-edec-468a-8c25-0a1be3b764a2', 'Guia de Acólito', 'Informações sobre ministério de acólito e vida litúrgica', '["Formação teológica básica","Preparação para os sacramentos","Funções litúrgicas do acólito","Compromisso com a paróquia","Encontros de formação regular","Participação em celebrações especiais","Vida espiritual e oração","Possibilidade de ordenação diaconal"]', NULL, '2026-02-09 12:47:30.338', '2026-02-09 12:47:30.338');
